Yes, serving files based on user input is extremely dangerous without proper validation. This is one of the most common ways attackers gain unauthorized access to sensitive files on your server.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();

// VULNERABLE: Direct path concatenation with user input
app.get('/files/:filename', (req, res) => {
  const filename = req.params.filename;
  const filePath = path.join(__dirname, 'uploads', filename);

  // No validation - attacker controls the path!
  fs.readFile(filePath, (err, data) => {
    if (err) {
      return res.status(404).send('File not found');
    }
    res.send(data);
  });
});

// VULNERABLE: Query parameter file access
app.get('/download', (req, res) => {
  const file = req.query.file;
  // Dangerous: path.join does NOT prevent traversal!
  const downloadPath = path.join('/var/app/documents', file);
  res.download(downloadPath);
});

app.listen(3000);
```

**Attack Payload**:
```text
GET /files/..%2F..%2F..%2Fetc%2Fpasswd HTTP/1.1
GET /files/../../../etc/shadow HTTP/1.1
GET /download?file=....//....//....//etc/passwd HTTP/1.1
GET /files/%2e%2e%2f%2e%2e%2f%2e%2e%2fetc%2fpasswd HTTP/1.1
```

**Why This Is Dangerous**:
- `path.join()` resolves `..` sequences, allowing escape from the intended directory
- URL-encoded traversal (`%2e%2e%2f` = `../`) bypasses naive string checks
- Attackers can read `/etc/passwd`, `/etc/shadow`, SSH keys, application configs, database credentials
- On Windows: `..\..\..\Windows\System32\config\SAM` exposes password hashes

**SECURE VERSION**:

```javascript
const express = require('express');
const fs = require('fs').promises;
const path = require('path');

const app = express();

// Define allowed base directory as absolute path
const UPLOADS_DIR = path.resolve(__dirname, 'uploads');

// Secure file serving with path validation
app.get('/files/:filename', async (req, res) => {
  try {
    const filename = req.params.filename;

    // DEFENSE 1: Reject obvious traversal attempts
    if (filename.includes('..') || filename.includes('\\') || filename.includes('/')) {
      console.warn(`Path traversal attempt blocked: ${filename} from ${req.ip}`);
      return res.status(400).json({ error: 'Invalid filename' });
    }

    // DEFENSE 2: Whitelist allowed characters
    const safeFilenamePattern = /^[a-zA-Z0-9_\-]+\.[a-zA-Z0-9]+$/;
    if (!safeFilenamePattern.test(filename)) {
      return res.status(400).json({ error: 'Invalid filename format' });
    }

    // DEFENSE 3: Resolve and validate final path
    const resolvedPath = path.resolve(UPLOADS_DIR, filename);

    // CRITICAL: Ensure resolved path is within allowed directory
    if (!resolvedPath.startsWith(UPLOADS_DIR + path.sep)) {
      console.error(`Path escape attempt: ${resolvedPath}`);
      return res.status(403).json({ error: 'Access denied' });
    }

    // DEFENSE 4: Check file exists before serving
    await fs.access(resolvedPath, fs.constants.R_OK);

    const data = await fs.readFile(resolvedPath);
    res.send(data);

  } catch (err) {
    // Don't reveal internal paths in errors
    res.status(404).json({ error: 'File not found' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Path Resolution Check**: Use `path.resolve()` then verify the result starts with the allowed directory using `startsWith(baseDir + path.sep)`
- **Input Validation**: Whitelist allowed characters and reject traversal sequences before processing
- **Absolute Path Comparison**: Compare absolute paths, not relative ones, to prevent bypass techniques
- **Fail Securely**: Return generic errors that don't reveal filesystem structure

Great questions! Subdirectories and encoding bypasses are common challenges. Attackers use double encoding, null bytes, and Unicode normalization tricks to evade filters. Here's a production-ready solution:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const fs = require('fs').promises;
const path = require('path');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

// Rate limiting to prevent enumeration attacks
const fileLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests' },
  standardHeaders: true,
  legacyHeaders: false
});

// Immutable configuration
const CONFIG = Object.freeze({
  BASE_DIR: path.resolve(process.env.FILES_BASE_DIR || './files'),
  MAX_PATH_LENGTH: 255,
  ALLOWED_EXTENSIONS: new Set(['.pdf', '.png', '.jpg', '.jpeg', '.gif', '.txt', '.docx']),
  LOG_LEVEL: process.env.NODE_ENV === 'production' ? 'warn' : 'debug'
});

// Comprehensive path sanitizer
class PathSanitizer {
  static normalizeAndValidate(userPath, baseDir) {
    // LAYER 1: Decode URL encoding (handles double encoding)
    let decoded = userPath;
    let previousDecoded;
    let iterations = 0;
    const maxIterations = 5;

    // Repeatedly decode until no change (catches double/triple encoding)
    do {
      previousDecoded = decoded;
      try {
        decoded = decodeURIComponent(decoded);
      } catch (e) {
        // Invalid encoding - reject
        return { valid: false, reason: 'Invalid URL encoding' };
      }
      iterations++;
    } while (decoded !== previousDecoded && iterations < maxIterations);

    // LAYER 2: Normalize Unicode (NFC normalization)
    decoded = decoded.normalize('NFC');

    // LAYER 3: Check for null bytes (used to truncate paths)
    if (decoded.includes('\0') || decoded.includes('%00')) {
      return { valid: false, reason: 'Null byte detected' };
    }

    // LAYER 4: Check path length
    if (decoded.length > CONFIG.MAX_PATH_LENGTH) {
      return { valid: false, reason: 'Path too long' };
    }

    // LAYER 5: Block traversal sequences (after all decoding)
    const traversalPatterns = [
      /\.\./g,           // Unix traversal
      /\.\.\\/g,         // Windows traversal
      /\.\.\//g,         // Forward slash
      /%2e%2e/gi,        // Encoded dots
      /%252e/gi,         // Double encoded
      /\.\.%00/g,        // Null byte combination
      /\.%00\./g         // Dot-null-dot
    ];

    for (const pattern of traversalPatterns) {
      if (pattern.test(decoded)) {
        return { valid: false, reason: 'Path traversal pattern detected' };
      }
    }

    // LAYER 6: Resolve to absolute path
    const resolvedPath = path.resolve(baseDir, decoded);

    // LAYER 7: Verify path is within allowed directory (CRITICAL CHECK)
    const normalizedBase = path.normalize(baseDir) + path.sep;
    const normalizedResolved = path.normalize(resolvedPath);

    if (!normalizedResolved.startsWith(normalizedBase)) {
      return { valid: false, reason: 'Path escapes base directory' };
    }

    // LAYER 8: Validate extension
    const ext = path.extname(resolvedPath).toLowerCase();
    if (!CONFIG.ALLOWED_EXTENSIONS.has(ext)) {
      return { valid: false, reason: 'File type not allowed' };
    }

    return { valid: true, path: resolvedPath };
  }
}

// Audit logger
const auditLog = (event, details, req) => {
  const logEntry = {
    timestamp: new Date().toISOString(),
    event,
    ip: req.ip,
    userAgent: req.get('User-Agent'),
    path: req.path,
    ...details
  };

  if (event.includes('BLOCKED') || event.includes('ERROR')) {
    console.error(JSON.stringify(logEntry));
  } else if (CONFIG.LOG_LEVEL === 'debug') {
    console.log(JSON.stringify(logEntry));
  }
};

// Production file serving endpoint with subdirectory support
app.get('/files/*', fileLimiter, async (req, res) => {
  const requestedPath = req.params[0]; // Captures everything after /files/

  if (!requestedPath) {
    return res.status(400).json({ error: 'No file specified' });
  }

  // Validate and sanitize path
  const validation = PathSanitizer.normalizeAndValidate(requestedPath, CONFIG.BASE_DIR);

  if (!validation.valid) {
    auditLog('FILE_ACCESS_BLOCKED', { 
      reason: validation.reason,
      requestedPath 
    }, req);
    return res.status(403).json({ error: 'Access denied' });
  }

  try {
    // Verify file exists and is a regular file (not symlink, device, etc.)
    const stats = await fs.lstat(validation.path);

    if (!stats.isFile()) {
      auditLog('FILE_ACCESS_BLOCKED', { 
        reason: 'Not a regular file',
        requestedPath 
      }, req);
      return res.status(403).json({ error: 'Access denied' });
    }

    // Check for symlink escape
    const realPath = await fs.realpath(validation.path);
    if (!realPath.startsWith(CONFIG.BASE_DIR + path.sep)) {
      auditLog('SYMLINK_ESCAPE_BLOCKED', { requestedPath }, req);
      return res.status(403).json({ error: 'Access denied' });
    }

    auditLog('FILE_ACCESS_GRANTED', { 
      file: path.basename(validation.path),
      size: stats.size 
    }, req);

    // Set security headers for file download
    res.setHeader('Content-Disposition', `attachment; filename="${path.basename(validation.path)}"`);
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('Cache-Control', 'private, no-cache');

    res.sendFile(validation.path);

  } catch (err) {
    if (err.code === 'ENOENT') {
      return res.status(404).json({ error: 'File not found' });
    }

    auditLog('FILE_ACCESS_ERROR', { error: err.message }, req);
    return res.status(500).json({ error: 'Internal server error' });
  }
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Serving files from: ${CONFIG.BASE_DIR}`);
});
```

**Defense in Depth Layers**:
1. **Recursive URL Decoding**: Handles double and triple encoding attacks (`%252e%252e%252f` → `../`)
2. **Unicode Normalization**: Prevents bypass via Unicode lookalike characters
3. **Null Byte Detection**: Blocks `file.txt%00.jpg` attacks that truncate paths
4. **Pattern Matching**: Catches traversal sequences after all decoding
5. **Absolute Path Resolution + Prefix Check**: The authoritative check that prevents escape
6. **Symlink Verification**: Uses `realpath()` to resolve symbolic links and verify the actual destination
7. **Extension Whitelist**: Only serve explicitly allowed file types
8. **File Type Verification**: Ensures target is a regular file, not a directory or device

**Additional Protections**:
- Rate limiting prevents file enumeration attacks (guessing file names)
- Audit logging creates forensic trail for incident response
- Security headers prevent content-type sniffing and force downloads
- Symlink check prevents attackers from creating links to sensitive files
- Environment-based configuration for secure production deployment

Your code is extremely vulnerable to path traversal attacks. This is the same vulnerability class that affected Fortinet devices in 2024 (CVE-2024-21762), impacting over 150,000 systems and enabling remote code execution.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.nio.file.*;

public class FileDownloadServlet extends HttpServlet {
    private static final String BASE_DIR = "/var/app/uploads/";

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String filename = request.getParameter("file");

        // VULNERABLE: Direct path concatenation with user input
        File file = new File(BASE_DIR + filename);

        if (file.exists()) {
            response.setContentType("application/octet-stream");
            response.setHeader("Content-Disposition", 
                "attachment; filename=\"" + file.getName() + "\"");

            try (FileInputStream fis = new FileInputStream(file);
                 OutputStream os = response.getOutputStream()) {
                byte[] buffer = new byte[4096];
                int bytesRead;
                while ((bytesRead = fis.read(buffer)) != -1) {
                    os.write(buffer, 0, bytesRead);
                }
            }
        } else {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
        }
    }
}
```

**Attack Payload**:
```text
GET /download?file=../../../etc/passwd HTTP/1.1
GET /download?file=....//....//....//etc/shadow HTTP/1.1
GET /download?file=..%2F..%2F..%2Fetc%2Fpasswd HTTP/1.1
GET /download?file=..\..\..\windows\system32\config\sam HTTP/1.1
```

**Why This Is Dangerous**:
- Attacker can escape the intended directory using `../` sequences
- URL encoding (`%2F`) can bypass naive filters
- On Windows, both `/` and `\` work as path separators
- Can read `/etc/passwd`, `/etc/shadow`, application configs, database credentials
- May enable reading application source code and encryption keys

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.nio.file.*;
import java.util.logging.Logger;
import java.util.regex.Pattern;

public class SecureFileDownloadServlet extends HttpServlet {
    private static final Logger logger = Logger.getLogger(SecureFileDownloadServlet.class.getName());
    private static final Path BASE_DIR = Paths.get("/var/app/uploads/").toAbsolutePath().normalize();
    private static final Pattern SAFE_FILENAME = Pattern.compile("^[a-zA-Z0-9][a-zA-Z0-9._-]{0,254}$");

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String filename = request.getParameter("file");
        String clientIP = request.getRemoteAddr();

        // DEFENSE 1: Input validation - whitelist allowed characters
        if (filename == null || !SAFE_FILENAME.matcher(filename).matches()) {
            logger.warning("Invalid filename attempt from " + clientIP + ": " + filename);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid filename");
            return;
        }

        // DEFENSE 2: Resolve and normalize the path
        Path requestedPath = BASE_DIR.resolve(filename).normalize();

        // DEFENSE 3: Canonical path check - verify file is within allowed directory
        if (!requestedPath.startsWith(BASE_DIR)) {
            logger.severe("Path traversal attempt from " + clientIP + ": " + filename);
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        // DEFENSE 4: Verify file exists and is a regular file (not symlink to outside)
        if (!Files.exists(requestedPath) || !Files.isRegularFile(requestedPath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
            return;
        }

        // DEFENSE 5: Check real path to prevent symlink attacks
        Path realPath = requestedPath.toRealPath();
        if (!realPath.startsWith(BASE_DIR.toRealPath())) {
            logger.severe("Symlink escape attempt from " + clientIP);
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        logger.info("File download: " + filename + " by " + clientIP);
        serveFile(requestedPath, response);
    }

    private void serveFile(Path filePath, HttpServletResponse response) throws IOException {
        response.setContentType("application/octet-stream");
        response.setHeader("Content-Disposition", 
            "attachment; filename=\"" + filePath.getFileName() + "\"");
        response.setContentLengthLong(Files.size(filePath));

        Files.copy(filePath, response.getOutputStream());
    }
}
```

**Key Security Controls**:
- **Whitelist validation**: Only allows alphanumeric filenames with limited special characters, rejecting any path components
- **Path normalization**: `normalize()` resolves `..` sequences before comparison
- **Directory containment check**: `startsWith(BASE_DIR)` ensures resolved path stays within allowed directory
- **Symlink protection**: `toRealPath()` resolves symbolic links to prevent escape via symlinks
- **Security logging**: All suspicious attempts are logged with client IP for incident response

Supporting subdirectories adds complexity but can be done securely with proper authorization checks and path validation. Here's a production-ready pattern that handles user-specific directories:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.nio.file.*;
import java.security.Principal;
import java.util.logging.Logger;
import java.util.regex.Pattern;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

public class SecureUserFileServlet extends HttpServlet {
    private static final Logger logger = Logger.getLogger(SecureUserFileServlet.class.getName());
    private static final Logger auditLogger = Logger.getLogger("AUDIT.FileAccess");

    private static final Path BASE_UPLOAD_DIR = Paths.get("/var/app/uploads/").toAbsolutePath().normalize();

    // Whitelist patterns - no path separators allowed in individual components
    private static final Pattern SAFE_PATH_COMPONENT = Pattern.compile("^[a-zA-Z0-9][a-zA-Z0-9._-]{0,63}$");
    private static final int MAX_PATH_DEPTH = 5;
    private static final long MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB

    // Rate limiting per user
    private static final ConcurrentHashMap<String, AtomicInteger> downloadCounts = new ConcurrentHashMap<>();
    private static final int MAX_DOWNLOADS_PER_MINUTE = 30;

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIP = request.getRemoteAddr();
        Principal userPrincipal = request.getUserPrincipal();

        // DEFENSE 1: Authentication required
        if (userPrincipal == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
            return;
        }

        String authenticatedUserId = userPrincipal.getName();

        // DEFENSE 2: Rate limiting per user
        if (!checkRateLimit(authenticatedUserId)) {
            logger.warning("Rate limit exceeded for user: " + authenticatedUserId);
            response.setHeader("Retry-After", "60");
            response.sendError(429, "Too many requests");
            return;
        }

        // Get path parameter: /files/user123/documents/file.pdf
        String pathInfo = request.getPathInfo();
        if (pathInfo == null || pathInfo.length() < 2) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST);
            return;
        }

        // DEFENSE 3: Parse and validate each path component individually
        String[] pathComponents = pathInfo.substring(1).split("/");

        if (pathComponents.length < 2 || pathComponents.length > MAX_PATH_DEPTH) {
            logger.warning("Invalid path depth from " + clientIP + ": " + pathInfo);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST);
            return;
        }

        // Validate each component against whitelist
        for (String component : pathComponents) {
            if (!SAFE_PATH_COMPONENT.matcher(component).matches()) {
                logger.warning("Invalid path component from " + clientIP + ": " + component);
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid path");
                return;
            }
        }

        String requestedUserId = pathComponents[0];

        // DEFENSE 4: Authorization - user can only access their own files
        // (or admin can access all)
        if (!authorizeAccess(authenticatedUserId, requestedUserId, request)) {
            auditLogger.warning(String.format(
                "UNAUTHORIZED_ACCESS_ATTEMPT user=%s target_user=%s path=%s ip=%s",
                authenticatedUserId, requestedUserId, pathInfo, clientIP));
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // DEFENSE 5: Build path safely using Path.resolve() for each component
        Path targetPath = BASE_UPLOAD_DIR;
        for (String component : pathComponents) {
            targetPath = targetPath.resolve(component);
        }
        targetPath = targetPath.normalize();

        // DEFENSE 6: Final containment check
        if (!targetPath.startsWith(BASE_UPLOAD_DIR)) {
            auditLogger.severe(String.format(
                "PATH_TRAVERSAL_BLOCKED user=%s path=%s resolved=%s ip=%s",
                authenticatedUserId, pathInfo, targetPath, clientIP));
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // DEFENSE 7: Verify it's a regular file (not directory, symlink escape, etc.)
        if (!Files.exists(targetPath) || !Files.isRegularFile(targetPath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND);
            return;
        }

        // DEFENSE 8: Resolve real path to catch symlink attacks
        Path realPath = targetPath.toRealPath();
        Path realBaseDir = BASE_UPLOAD_DIR.toRealPath();
        if (!realPath.startsWith(realBaseDir)) {
            auditLogger.severe(String.format(
                "SYMLINK_ESCAPE_BLOCKED user=%s target=%s real=%s ip=%s",
                authenticatedUserId, targetPath, realPath, clientIP));
            response.sendError(HttpServletResponse.SC_FORBIDDEN);
            return;
        }

        // DEFENSE 9: File size check to prevent DoS
        long fileSize = Files.size(realPath);
        if (fileSize > MAX_FILE_SIZE) {
            response.sendError(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE);
            return;
        }

        // Audit log successful access
        auditLogger.info(String.format(
            "FILE_DOWNLOAD user=%s file=%s size=%d ip=%s",
            authenticatedUserId, realPath.getFileName(), fileSize, clientIP));

        serveFileSecurely(realPath, response);
    }

    private boolean authorizeAccess(String authenticatedUser, String targetUser, 
                                    HttpServletRequest request) {
        // User can access their own files
        if (authenticatedUser.equals(targetUser)) {
            return true;
        }

        // Admin role can access all files
        if (request.isUserInRole("ADMIN") || request.isUserInRole("FILE_AUDITOR")) {
            return true;
        }

        // Check for explicit sharing permissions (from database)
        return checkSharingPermission(authenticatedUser, targetUser);
    }

    private boolean checkSharingPermission(String requestor, String owner) {
        // In production: query database for sharing permissions
        // SELECT 1 FROM file_shares WHERE owner_id = ? AND shared_with = ? AND expires_at > NOW()
        return false;
    }

    private boolean checkRateLimit(String userId) {
        AtomicInteger count = downloadCounts.computeIfAbsent(userId, k -> new AtomicInteger(0));
        return count.incrementAndGet() <= MAX_DOWNLOADS_PER_MINUTE;
    }

    private void serveFileSecurely(Path filePath, HttpServletResponse response) throws IOException {
        String contentType = Files.probeContentType(filePath);
        if (contentType == null) {
            contentType = "application/octet-stream";
        }

        // DEFENSE 10: Security headers
        response.setContentType(contentType);
        response.setHeader("Content-Disposition", 
            "attachment; filename=\"" + sanitizeFilename(filePath.getFileName().toString()) + "\"");
        response.setContentLengthLong(Files.size(filePath));
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Cache-Control", "private, no-cache, no-store");
        response.setHeader("Content-Security-Policy", "default-src 'none'");

        Files.copy(filePath, response.getOutputStream());
    }

    private String sanitizeFilename(String filename) {
        // Remove any characters that could cause header injection
        return filename.replaceAll("[^a-zA-Z0-9._-]", "_");
    }

    // Reset rate limits every minute (call from scheduled task)
    public static void resetRateLimits() {
        downloadCounts.clear();
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Gate**:
```java
if (userPrincipal == null) {
    response.sendError(HttpServletResponse.SC_UNAUTHORIZED);
    return;
}
```

2. **Component-by-Component Validation**:
```java
// Never trust combined paths - validate each piece
for (String component : pathComponents) {
    if (!SAFE_PATH_COMPONENT.matcher(component).matches()) {
        // Rejects: "..", ".", empty, encoded sequences, special chars
        response.sendError(HttpServletResponse.SC_BAD_REQUEST);
        return;
    }
}
```

3. **Authorization Before File Access**:
```java
// IDOR prevention - verify user has rights to target directory
if (!authorizeAccess(authenticatedUserId, requestedUserId, request)) {
    auditLogger.warning("UNAUTHORIZED_ACCESS_ATTEMPT...");
    response.sendError(HttpServletResponse.SC_FORBIDDEN);
    return;
}
```

**Additional Protections**:

- **Chroot/Container Isolation**: Run file-serving component in container with read-only mount to upload directory only
- **File Type Restrictions**: Validate file extensions and MIME types against allowlist
- **Virus Scanning**: Integrate ClamAV or similar for uploaded files
- **Monitoring Alerts**: Alert on multiple 403s from same IP (attack indicator)
- **WAF Rules**: Deploy ModSecurity rules to block common traversal patterns at edge
- **Scheduled Cleanup**: Remove rate limit entries and temporary files periodically

**Deployment Configuration**:
```java
// In production, externalize these settings
public class FileServiceConfig {
    @Value("${file.upload.basedir}")
    private String uploadBaseDir;

    @Value("${file.max.size:104857600}")
    private long maxFileSize;

    @Value("${file.rate.limit:30}")
    private int rateLimit;

    @Value("${file.allowed.extensions:pdf,docx,xlsx,png,jpg}")
    private List<String> allowedExtensions;
}
