File serving is a common attack vector for path traversal vulnerabilities. If you don't properly validate and sanitize file paths, attackers can escape your intended directory and access sensitive system files.

**VULNERABLE CODE**:

```go
package main

import (
	"io"
	"net/http"
	"os"
	"path/filepath"
)

const uploadDir = "/var/www/uploads"

func serveFile(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: Directly using user input in file path
	filename := r.URL.Query().Get("file")

	// This concatenation is dangerous!
	filePath := filepath.Join(uploadDir, filename)

	// No validation - attacker can traverse directories
	file, err := os.Open(filePath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	w.Header().Set("Content-Type", "application/octet-stream")
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", serveFile)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```bash
# Read /etc/passwd
curl "http://target.com/download?file=../../../etc/passwd"

# Read application configuration
curl "http://target.com/download?file=../../config/database.yml"

# Access SSH keys
curl "http://target.com/download?file=../../../root/.ssh/id_rsa"

# URL-encoded traversal to bypass basic filters
curl "http://target.com/download?file=..%2F..%2F..%2Fetc%2Fpasswd"
```

**Why This Is Dangerous**:
- `filepath.Join()` does NOT prevent path traversal - it simply joins paths
- Attackers can use `../` sequences to escape the upload directory
- Sensitive files like `/etc/passwd`, SSH keys, and config files can be leaked
- On Windows, both `../` and `..\` work for traversal
- URL encoding (`%2F` for `/`) can bypass naive string checks

**SECURE VERSION**:

```go
package main

import (
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadDir = "/var/www/uploads"

func serveFileSafe(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("file")

	// SECURITY: Validate filename is not empty
	if filename == "" {
		http.Error(w, "Missing file parameter", http.StatusBadRequest)
		return
	}

	// SECURITY: Get only the base filename, stripping any path components
	cleanName := filepath.Base(filename)

	// SECURITY: Reject if Base() returns "." (empty or just dots)
	if cleanName == "." || cleanName == ".." {
		log.Printf("Path traversal attempt blocked: %s from %s", filename, r.RemoteAddr)
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// SECURITY: Build the full path
	filePath := filepath.Join(uploadDir, cleanName)

	// SECURITY: Resolve to absolute path and verify it's within uploadDir
	absPath, err := filepath.Abs(filePath)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	absUploadDir, _ := filepath.Abs(uploadDir)
	if !strings.HasPrefix(absPath, absUploadDir+string(os.PathSeparator)) {
		log.Printf("Path traversal attempt blocked: %s resolved to %s from %s", 
			filename, absPath, r.RemoteAddr)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// SECURITY: Verify file exists and is a regular file (not symlink)
	fileInfo, err := os.Lstat(absPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	if !fileInfo.Mode().IsRegular() {
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	file, err := os.Open(absPath)
	if err != nil {
		http.Error(w, "Cannot read file", http.StatusInternalServerError)
		return
	}
	defer file.Close()

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", "attachment; filename="+cleanName)
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", serveFileSafe)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **filepath.Base()**: Extracts only the filename, removing all directory components including `../`
- **Absolute path verification**: Resolves symlinks and verifies the final path is within the allowed directory
- **strings.HasPrefix() check**: Ensures the resolved path starts with the upload directory
- **Lstat() instead of Stat()**: Detects symlinks that could point outside the allowed directory
- **Logging**: Records attempted attacks for security monitoring

Supporting subdirectories adds complexity because you need to allow `/` in paths while preventing `../` traversal. Here's a production-ready pattern with proper user isolation and comprehensive security controls.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/subtle"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"

	"golang.org/x/time/rate"
)

type FileServer struct {
	baseDir       string
	allowedExts   map[string]bool
	maxPathDepth  int
	rateLimiters  map[string]*rate.Limiter
	auditLogger   *log.Logger
}

type SecurityAuditLog struct {
	Timestamp   string `json:"timestamp"`
	Event       string `json:"event"`
	UserID      string `json:"user_id"`
	RemoteAddr  string `json:"remote_addr"`
	RequestPath string `json:"request_path"`
	ResolvedPath string `json:"resolved_path,omitempty"`
	Blocked     bool   `json:"blocked"`
	Reason      string `json:"reason,omitempty"`
}

func NewFileServer(baseDir string) (*FileServer, error) {
	absBase, err := filepath.Abs(baseDir)
	if err != nil {
		return nil, fmt.Errorf("invalid base directory: %w", err)
	}

	// Verify base directory exists and is a directory
	info, err := os.Stat(absBase)
	if err != nil || !info.IsDir() {
		return nil, fmt.Errorf("base directory does not exist or is not a directory")
	}

	auditFile, err := os.OpenFile("/var/log/app/file_access.log", 
		os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0600)
	if err != nil {
		return nil, fmt.Errorf("cannot open audit log: %w", err)
	}

	return &FileServer{
		baseDir:      absBase,
		allowedExts:  map[string]bool{".pdf": true, ".jpg": true, ".png": true, ".docx": true},
		maxPathDepth: 5,
		rateLimiters: make(map[string]*rate.Limiter),
		auditLogger:  log.New(auditFile, "", 0),
	}, nil
}

func (fs *FileServer) logAudit(event SecurityAuditLog) {
	event.Timestamp = time.Now().UTC().Format(time.RFC3339)
	data, _ := json.Marshal(event)
	fs.auditLogger.Println(string(data))
}

// SECURITY: Strict filename pattern - alphanumeric, hyphens, underscores, dots
var safeFilenamePattern = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9._-]*$`)

func (fs *FileServer) validatePathComponent(component string) error {
	if component == "" || component == "." || component == ".." {
		return fmt.Errorf("invalid path component")
	}
	if !safeFilenamePattern.MatchString(component) {
		return fmt.Errorf("invalid characters in path")
	}
	if len(component) > 255 {
		return fmt.Errorf("path component too long")
	}
	return nil
}

func (fs *FileServer) sanitizePath(userPath string) (string, error) {
	// SECURITY: Clean the path first (resolves . and .. sequences)
	cleaned := filepath.Clean(userPath)

	// SECURITY: Reject if cleaned path starts with .. or /
	if strings.HasPrefix(cleaned, "..") || filepath.IsAbs(cleaned) {
		return "", fmt.Errorf("path traversal detected")
	}

	// SECURITY: Split and validate each component
	components := strings.Split(cleaned, string(os.PathSeparator))

	if len(components) > fs.maxPathDepth {
		return "", fmt.Errorf("path too deep")
	}

	for _, comp := range components {
		if err := fs.validatePathComponent(comp); err != nil {
			return "", err
		}
	}

	return cleaned, nil
}

func (fs *FileServer) ServeFile(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	userID := getUserIDFromContext(ctx) // From auth middleware
	remoteAddr := r.RemoteAddr

	// SECURITY: Rate limiting per user
	if !fs.checkRateLimit(userID) {
		fs.logAudit(SecurityAuditLog{
			Event:      "rate_limit_exceeded",
			UserID:     userID,
			RemoteAddr: remoteAddr,
			Blocked:    true,
			Reason:     "rate limit exceeded",
		})
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	requestPath := r.URL.Query().Get("path")

	// SECURITY: User isolation - prepend user's directory
	userBasePath := filepath.Join(fs.baseDir, "users", userID)

	// Verify user directory exists
	if _, err := os.Stat(userBasePath); os.IsNotExist(err) {
		http.Error(w, "User directory not found", http.StatusNotFound)
		return
	}

	// SECURITY: Sanitize the requested path
	sanitizedPath, err := fs.sanitizePath(requestPath)
	if err != nil {
		fs.logAudit(SecurityAuditLog{
			Event:       "path_traversal_attempt",
			UserID:      userID,
			RemoteAddr:  remoteAddr,
			RequestPath: requestPath,
			Blocked:     true,
			Reason:      err.Error(),
		})
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	// SECURITY: Build full path within user's directory
	fullPath := filepath.Join(userBasePath, sanitizedPath)

	// SECURITY: Final verification - resolve to absolute and check containment
	absPath, err := filepath.Abs(fullPath)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	absUserBase, _ := filepath.Abs(userBasePath)

	// SECURITY: Constant-time comparison for the prefix check
	if !strings.HasPrefix(absPath, absUserBase+string(os.PathSeparator)) {
		fs.logAudit(SecurityAuditLog{
			Event:        "path_escape_attempt",
			UserID:       userID,
			RemoteAddr:   remoteAddr,
			RequestPath:  requestPath,
			ResolvedPath: absPath,
			Blocked:      true,
			Reason:       "resolved path outside user directory",
		})
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// SECURITY: Use Lstat to detect symlinks
	fileInfo, err := os.Lstat(absPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	// SECURITY: Reject symlinks (could point outside allowed directory)
	if fileInfo.Mode()&os.ModeSymlink != 0 {
		fs.logAudit(SecurityAuditLog{
			Event:        "symlink_access_blocked",
			UserID:       userID,
			RemoteAddr:   remoteAddr,
			RequestPath:  requestPath,
			ResolvedPath: absPath,
			Blocked:      true,
			Reason:       "symlink access not allowed",
		})
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	if !fileInfo.Mode().IsRegular() {
		http.Error(w, "Not a regular file", http.StatusBadRequest)
		return
	}

	// SECURITY: Verify file extension is allowed
	ext := strings.ToLower(filepath.Ext(absPath))
	if !fs.allowedExts[ext] {
		fs.logAudit(SecurityAuditLog{
			Event:       "disallowed_extension",
			UserID:      userID,
			RemoteAddr:  remoteAddr,
			RequestPath: requestPath,
			Blocked:     true,
			Reason:      fmt.Sprintf("extension %s not allowed", ext),
		})
		http.Error(w, "File type not allowed", http.StatusForbidden)
		return
	}

	// SUCCESS: Serve the file
	file, err := os.Open(absPath)
	if err != nil {
		http.Error(w, "Cannot read file", http.StatusInternalServerError)
		return
	}
	defer file.Close()

	fs.logAudit(SecurityAuditLog{
		Event:        "file_access",
		UserID:       userID,
		RemoteAddr:   remoteAddr,
		RequestPath:  requestPath,
		ResolvedPath: absPath,
		Blocked:      false,
	})

	// SECURITY: Set proper headers
	w.Header().Set("Content-Type", getContentType(ext))
	w.Header().Set("Content-Disposition", 
		fmt.Sprintf("attachment; filename=%q", filepath.Base(absPath)))
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "private, no-cache")

	io.Copy(w, file)
}

func (fs *FileServer) checkRateLimit(userID string) bool {
	limiter, exists := fs.rateLimiters[userID]
	if !exists {
		limiter = rate.NewLimiter(rate.Every(time.Second), 10) // 10 requests per second
		fs.rateLimiters[userID] = limiter
	}
	return limiter.Allow()
}

func getContentType(ext string) string {
	types := map[string]string{
		".pdf":  "application/pdf",
		".jpg":  "image/jpeg",
		".png":  "image/png",
		".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
	}
	if ct, ok := types[ext]; ok {
		return ct
	}
	return "application/octet-stream"
}

func getUserIDFromContext(ctx context.Context) string {
	if userID, ok := ctx.Value("user_id").(string); ok {
		return userID
	}
	return "anonymous"
}

func main() {
	fs, err := NewFileServer("/var/www/uploads")
	if err != nil {
		log.Fatalf("Failed to initialize file server: %v", err)
	}

	http.HandleFunc("/download", fs.ServeFile)
	log.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}
```

**Defense in Depth Layers**:

1. **Input Validation Layer**:
```go
// Regex pattern allows only safe characters
var safeFilenamePattern = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9._-]*$`)

// Each path component is validated individually
for _, comp := range components {
    if err := fs.validatePathComponent(comp); err != nil {
        return "", err
    }
}
```

2. **Path Canonicalization Layer**:
```go
// filepath.Clean resolves . and .. but we still verify the result
cleaned := filepath.Clean(userPath)

// Absolute path resolution catches edge cases
absPath, err := filepath.Abs(fullPath)

// Final containment check
if !strings.HasPrefix(absPath, absUserBase+string(os.PathSeparator)) {
    // Block access
}
```

3. **User Isolation Layer**:
```go
// Each user is confined to their own directory
userBasePath := filepath.Join(fs.baseDir, "users", userID)

// Even if traversal succeeds, they can't access other users' files
```

**Additional Protections**:
- **Symlink rejection**: Prevents attackers from creating symlinks that point outside allowed directories
- **File extension allowlist**: Only explicitly permitted file types can be served
- **Rate limiting**: Prevents brute-force enumeration of file paths
- **Comprehensive audit logging**: All access attempts (successful and blocked) are logged with full context for incident response
- **Security headers**: `X-Content-Type-Options: nosniff` prevents MIME-sniffing attacks, `Content-Disposition: attachment` forces download rather than inline rendering

File download endpoints are extremely dangerous if implemented incorrectly. Path traversal vulnerabilities allow attackers to escape intended directories and access any file on the system - this was exploited in CVE-2024-21762 affecting Fortinet devices, compromising 150,000+ systems worldwide.

**VULNERABLE CODE**:

```php
<?php
// DANGEROUS: Never use user input directly in file paths!

class FileDownloadController {
    private $uploadDir = '/var/www/uploads/';

    public function downloadFile() {
        // User-controlled filename with NO validation
        $filename = $_GET['file'];

        // Direct concatenation - PATH TRAVERSAL VULNERABILITY
        $filepath = $this->uploadDir . $filename;

        // No existence or permission check
        if (file_exists($filepath)) {
            header('Content-Type: application/octet-stream');
            header('Content-Disposition: attachment; filename="' . basename($filename) . '"');
            header('Content-Length: ' . filesize($filepath));

            // Reads ANY file the web server can access
            readfile($filepath);
            exit;
        } else {
            http_response_code(404);
            echo "File not found";
        }
    }
}

// Usage
$controller = new FileDownloadController();
$controller->downloadFile();
?>
```

**Attack Payloads**:
```text
# Read system password file
?file=../../../etc/passwd

# Read PHP configuration
?file=../../../etc/php/8.2/apache2/php.ini

# Read application credentials
?file=../../config/database.php

# Read SSL private keys
?file=../../../etc/ssl/private/server.key

# Double encoding bypass
?file=..%252f..%252f..%252fetc/passwd

# Null byte injection (older PHP)
?file=../../../etc/passwd%00.jpg
```

**Why This Is Dangerous**:
- User input directly controls file path with no sanitization
- `../` sequences allow escaping the intended upload directory
- Attackers can read sensitive files: `/etc/passwd`, application configs, database credentials
- Can expose SSL private keys, session files, and source code
- May allow reading files containing database credentials leading to full compromise

**SECURE VERSION**:

```php
<?php
class SecureFileDownloadController {
    private $uploadDir;
    private $allowedExtensions = ['pdf', 'png', 'jpg', 'jpeg', 'gif', 'txt', 'doc', 'docx'];
    private $pdo;

    public function __construct(PDO $pdo) {
        // Use realpath to resolve the actual directory
        $this->uploadDir = realpath(__DIR__ . '/../uploads');
        if ($this->uploadDir === false) {
            throw new RuntimeException('Upload directory does not exist');
        }
        $this->pdo = $pdo;
    }

    public function downloadFile(int $userId, string $fileId): void {
        // DEFENSE 1: Validate file ID format (UUID only)
        if (!preg_match('/^[a-f0-9]{8}-[a-f0-9]{4}-4[a-f0-9]{3}-[89ab][a-f0-9]{3}-[a-f0-9]{12}$/i', $fileId)) {
            $this->logSecurityEvent('invalid_file_id', $userId, $fileId);
            $this->sendError(400, 'Invalid file identifier');
            return;
        }

        // DEFENSE 2: Database lookup - only return files user owns
        $stmt = $this->pdo->prepare(
            'SELECT filename, original_name, mime_type FROM uploads 
             WHERE file_id = :file_id AND user_id = :user_id AND deleted_at IS NULL'
        );
        $stmt->execute(['file_id' => $fileId, 'user_id' => $userId]);
        $fileRecord = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$fileRecord) {
            $this->logSecurityEvent('unauthorized_access_attempt', $userId, $fileId);
            $this->sendError(404, 'File not found');
            return;
        }

        // DEFENSE 3: Construct path and validate with realpath
        $storedFilename = basename($fileRecord['filename']); // Extra safety
        $fullPath = $this->uploadDir . DIRECTORY_SEPARATOR . $storedFilename;
        $realPath = realpath($fullPath);

        // DEFENSE 4: Verify file is within allowed directory
        if ($realPath === false || strpos($realPath, $this->uploadDir) !== 0) {
            $this->logSecurityEvent('path_traversal_blocked', $userId, $fullPath);
            $this->sendError(403, 'Access denied');
            return;
        }

        // DEFENSE 5: Validate file extension
        $extension = strtolower(pathinfo($realPath, PATHINFO_EXTENSION));
        if (!in_array($extension, $this->allowedExtensions, true)) {
            $this->logSecurityEvent('blocked_extension', $userId, $extension);
            $this->sendError(403, 'File type not allowed');
            return;
        }

        // DEFENSE 6: Verify file exists and is readable
        if (!is_file($realPath) || !is_readable($realPath)) {
            $this->sendError(404, 'File not available');
            return;
        }

        // Log successful download
        $this->logDownload($userId, $fileId, $realPath);

        // Send file with secure headers
        $this->sendFile($realPath, $fileRecord['original_name'], $fileRecord['mime_type']);
    }

    private function sendFile(string $path, string $displayName, string $mimeType): void {
        // Sanitize display name for Content-Disposition
        $safeName = preg_replace('/[^a-zA-Z0-9._-]/', '_', $displayName);

        header('Content-Type: ' . $mimeType);
        header('Content-Disposition: attachment; filename="' . $safeName . '"');
        header('Content-Length: ' . filesize($path));
        header('X-Content-Type-Options: nosniff');
        header('Cache-Control: private, no-cache, no-store, must-revalidate');

        readfile($path);
        exit;
    }

    private function sendError(int $code, string $message): void {
        http_response_code($code);
        header('Content-Type: application/json');
        echo json_encode(['error' => $message]);
    }

    private function logSecurityEvent(string $event, int $userId, string $details): void {
        error_log(sprintf(
            '[SECURITY] %s | event=%s | user=%d | details=%s | ip=%s',
            date('Y-m-d H:i:s'),
            $event,
            $userId,
            $details,
            $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ));
    }

    private function logDownload(int $userId, string $fileId, string $path): void {
        $stmt = $this->pdo->prepare(
            'INSERT INTO download_log (user_id, file_id, downloaded_at, ip_address) 
             VALUES (:user_id, :file_id, NOW(), :ip)'
        );
        $stmt->execute([
            'user_id' => $userId,
            'file_id' => $fileId,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]);
    }
}
?>
```

**Key Security Controls**:
- **Database-driven access**: Files are looked up by UUID and user ownership, not user-supplied filenames
- **realpath() validation**: Resolves symbolic links and verifies the actual path stays within upload directory
- **Directory containment check**: Ensures `strpos($realPath, $this->uploadDir) === 0` prevents escaping
- **Extension whitelist**: Only explicitly allowed file types can be downloaded
- **Security logging**: All access attempts and blocked attacks are logged for monitoring

Supporting subdirectories adds complexity but can be done securely. The key is maintaining strict path validation while allowing legitimate hierarchical access. Many breaches like CVE-2024-21762 exploited insufficient validation when directory structures were involved.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

namespace App\Services;

use PDO;
use RuntimeException;
use InvalidArgumentException;
use Psr\Log\LoggerInterface;

class SecureFileService {
    private string $baseUploadDir;
    private PDO $pdo;
    private LoggerInterface $logger;
    private array $allowedExtensions;
    private array $mimeTypeMap;
    private int $maxPathDepth = 5;

    public function __construct(
        PDO $pdo,
        LoggerInterface $logger,
        string $uploadBasePath,
        array $allowedExtensions = ['pdf', 'png', 'jpg', 'jpeg', 'gif', 'txt']
    ) {
        $this->pdo = $pdo;
        $this->logger = $logger;
        $this->allowedExtensions = array_map('strtolower', $allowedExtensions);

        // Resolve and validate base directory at construction
        $realBase = realpath($uploadBasePath);
        if ($realBase === false || !is_dir($realBase)) {
            throw new RuntimeException('Invalid upload base directory');
        }
        $this->baseUploadDir = $realBase;

        $this->mimeTypeMap = [
            'pdf' => 'application/pdf',
            'png' => 'image/png',
            'jpg' => 'image/jpeg',
            'jpeg' => 'image/jpeg',
            'gif' => 'image/gif',
            'txt' => 'text/plain'
        ];
    }

    /**
     * Download a file with full path traversal protection
     */
    public function downloadUserFile(int $userId, string $requestedPath): void {
        $context = [
            'user_id' => $userId,
            'requested_path' => $requestedPath,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown'
        ];

        try {
            // LAYER 1: Sanitize and validate path format
            $sanitizedPath = $this->sanitizePath($requestedPath);

            // LAYER 2: Verify user has access to this path via database
            $fileRecord = $this->verifyUserAccess($userId, $sanitizedPath);
            if (!$fileRecord) {
                $this->logger->warning('Unauthorized file access attempt', $context);
                $this->sendJsonError(403, 'Access denied');
                return;
            }

            // LAYER 3: Resolve and validate actual filesystem path
            $resolvedPath = $this->resolveSecurePath($userId, $sanitizedPath);
            if ($resolvedPath === null) {
                $this->logger->error('Path traversal attack detected', $context);
                $this->sendJsonError(403, 'Invalid path');
                return;
            }

            // LAYER 4: Validate file type and integrity
            if (!$this->validateFile($resolvedPath)) {
                $this->logger->warning('File validation failed', array_merge($context, ['path' => $resolvedPath]));
                $this->sendJsonError(403, 'File type not allowed');
                return;
            }

            // LAYER 5: Rate limiting check
            if (!$this->checkDownloadRateLimit($userId)) {
                $this->logger->warning('Download rate limit exceeded', $context);
                $this->sendJsonError(429, 'Too many download requests');
                return;
            }

            // Log successful download
            $this->auditDownload($userId, $fileRecord['id'], $resolvedPath);

            // Serve the file
            $this->streamFile($resolvedPath, $fileRecord['original_name']);

        } catch (InvalidArgumentException $e) {
            $this->logger->warning('Invalid path format', array_merge($context, ['error' => $e->getMessage()]));
            $this->sendJsonError(400, 'Invalid request');
        } catch (\Throwable $e) {
            $this->logger->error('File download error', array_merge($context, ['error' => $e->getMessage()]));
            $this->sendJsonError(500, 'Internal error');
        }
    }

    /**
     * DEFENSE: Multi-layer path sanitization
     */
    private function sanitizePath(string $path): string {
        // Remove null bytes (CVE-2006-7243 style attacks)
        $path = str_replace("\0", '', $path);

        // Decode URL encoding layers (prevent double-encoding bypass)
        $decoded = $path;
        $maxIterations = 3;
        for ($i = 0; $i < $maxIterations; $i++) {
            $newDecoded = urldecode($decoded);
            if ($newDecoded === $decoded) break;
            $decoded = $newDecoded;
        }
        $path = $decoded;

        // Normalize directory separators
        $path = str_replace(['\\', '/'], DIRECTORY_SEPARATOR, $path);

        // Block dangerous patterns
        $dangerousPatterns = [
            '..',           // Directory traversal
            './',           // Current directory reference
            '/.',           // Hidden files on Unix
            '~',            // Home directory expansion
            ':',            // Windows drive letters / alternate data streams
            '*', '?',       // Wildcards
            '<', '>', '|',  // Shell metacharacters
            '\$',           // Variable expansion
            '`',            // Command substitution
        ];

        foreach ($dangerousPatterns as $pattern) {
            if (strpos($path, $pattern) !== false) {
                throw new InvalidArgumentException('Invalid path characters detected');
            }
        }

        // Validate path depth
        $segments = explode(DIRECTORY_SEPARATOR, trim($path, DIRECTORY_SEPARATOR));
        if (count($segments) > $this->maxPathDepth) {
            throw new InvalidArgumentException('Path too deep');
        }

        // Validate each segment
        foreach ($segments as $segment) {
            if ($segment === '' || $segment === '.' || $segment === '..') {
                throw new InvalidArgumentException('Invalid path segment');
            }
            // Only allow alphanumeric, dash, underscore, dot (not at start)
            if (!preg_match('/^[a-zA-Z0-9][a-zA-Z0-9._-]*$/', $segment)) {
                throw new InvalidArgumentException('Invalid characters in path segment');
            }
        }

        return implode(DIRECTORY_SEPARATOR, $segments);
