  }

  // DEFENSE 2: Extract only the basename (removes all path components)
  const sanitizedFilename = path.basename(filename);

  // DEFENSE 3: Validate file extension
  const ext = path.extname(sanitizedFilename).toLowerCase();
  if (!ALLOWED_EXTENSIONS.includes(ext)) {
    return res.status(400).json({ error: 'File type not allowed' });
  }

  // DEFENSE 4: Construct path and verify it's within allowed directory
  const filePath = path.resolve(UPLOADS_DIR, sanitizedFilename);

  // CRITICAL: Verify the resolved path starts with our uploads directory
  if (!filePath.startsWith(UPLOADS_DIR + path.sep)) {
    console.warn(`Path traversal attempt blocked: ${filename} -> ${filePath}`);
    return res.status(403).json({ error: 'Access denied' });
  }

  // DEFENSE 5: Check file exists before serving
  if (!fs.existsSync(filePath)) {
