import javax.servlet.http.*;
import java.io.*;
import java.nio.file.*;
import java.util.logging.Logger;
import java.util.regex.Pattern;
import java.security.MessageDigest;
import java.util.Base64;

public class ProductionFileAccessServlet extends HttpServlet {
    private static final Logger LOGGER = Logger.getLogger(ProductionFileAccessServlet.class.getName());
    private static final Logger SECURITY_LOGGER = Logger.getLogger("SECURITY_AUDIT");

    private static final Path BASE_UPLOAD_DIR = Paths.get("/var/www/uploads").toAbsolutePath().normalize();

    // Whitelist pattern for safe path segments
    private static final Pattern SAFE_PATH_SEGMENT = Pattern.compile("^[a-zA-Z0-9][a-zA-Z0-9._-]*$");
    private static final int MAX_PATH_DEPTH = 5;
    private static final long MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB

    // Rate limiter (simplified - use Redis in production)
    private static final java.util.concurrent.ConcurrentHashMap<String, Long> rateLimitMap = 
        new java.util.concurrent.ConcurrentHashMap<>();

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIP = getClientIP(request);
        String sessionId = request.getSession().getId();

        // LAYER 1: Rate limiting
        if (isRateLimited(clientIP)) {
            SECURITY_LOGGER.warning("Rate limit exceeded: " + clientIP);
            response.sendError(429, "Too many requests");
            return;
        }

        // LAYER 2: Authentication check
        String userId = (String) request.getSession().getAttribute("userId");
        if (userId == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Authentication required");
            return;
        }

        String requestedPath = request.getParameter("path");

        // LAYER 3: Input validation
        PathValidationResult validation = validateAndSanitizePath(requestedPath, userId);
        if (!validation.isValid()) {
            SECURITY_LOGGER.warning(String.format(
                "Path validation failed | User: %s | IP: %s | Path: %s | Reason: %s",
                userId, clientIP, requestedPath, validation.getReason()));
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid path");
            return;
        }

        Path resolvedPath = validation.getResolvedPath();

        // LAYER 4: Authorization - verify user owns this file
        if (!isUserAuthorizedForPath(userId, resolvedPath)) {
            SECURITY_LOGGER.severe(String.format(
                "Unauthorized access attempt | User: %s | IP: %s | Path: %s",
                userId, clientIP, resolvedPath));
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        // LAYER 5: File existence and type validation
        if (!Files.exists(resolvedPath)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found");
            return;
        }

        if (!Files.isRegularFile(resolvedPath)) {
            SECURITY_LOGGER.warning("Attempt to access non-file: " + resolvedPath);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Not a file");
            return;
        }

        // LAYER 6: Symlink protection
        if (Files.isSymbolicLink(resolvedPath)) {
            Path realPath = resolvedPath.toRealPath();
            if (!realPath.startsWith(BASE_UPLOAD_DIR)) {
                SECURITY_LOGGER.severe("Symlink escape attempt: " + resolvedPath + " -> " + realPath);
                response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
                return;
            }
        }

        // LAYER 7: File size check
        long fileSize = Files.size(resolvedPath);
        if (fileSize > MAX_FILE_SIZE) {
            response.sendError(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE, "File too large");
            return;
        }

        // Serve file with security headers
        String safeFilename = resolvedPath.getFileName().toString();
        String contentType = getSecureContentType(safeFilename);

        response.setContentType(contentType);
        response.setContentLengthLong(fileSize);
        response.setHeader("Content-Disposition", 
            "attachment; filename=\"" + sanitizeFilenameForHeader(safeFilename) + "\"");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Cache-Control", "private, no-cache, no-store");
        response.setHeader("Content-Security-Policy", "default-src 'none'");

        try (InputStream is = Files.newInputStream(resolvedPath)) {
            byte[] buffer = new byte[8192];
            int bytesRead;
            OutputStream os = response.getOutputStream();
            while ((bytesRead = is.read(buffer)) != -1) {
                os.write(buffer, 0, bytesRead);
            }
        }

        // Audit log successful access
        SECURITY_LOGGER.info(String.format(
            "File accessed | User: %s | IP: %s | File: %s | Size: %d",
            userId, clientIP, resolvedPath.getFileName(), fileSize));
    }

    private PathValidationResult validateAndSanitizePath(String requestedPath, String userId) {
        if (requestedPath == null || requestedPath.isEmpty()) {
            return PathValidationResult.invalid("Path is empty");
        }

        // Decode and check for null bytes
        if (requestedPath.contains("\0") || requestedPath.contains("%00")) {
            return PathValidationResult.invalid("Null byte detected");
        }

        // Check for obvious traversal attempts before processing
        if (requestedPath.contains("..") || 
            requestedPath.contains("%2e") || 
            requestedPath.contains("%252e")) {
            return PathValidationResult.invalid("Traversal sequence detected");
        }

        // Split into segments and validate each
        String[] segments = requestedPath.split("[\\/]+");

        if (segments.length > MAX_PATH_DEPTH) {
            return PathValidationResult.invalid("Path too deep");
        }

        // Rebuild path from validated segments
        Path safePath = BASE_UPLOAD_DIR;
        for (String segment : segments) {
            if (segment.isEmpty()) continue;

            // Validate each segment against whitelist
            if (!SAFE_PATH_SEGMENT.matcher(segment).matches()) {
                return PathValidationResult.invalid("Invalid path segment: " + segment);
            }

            // Check for hidden files
            if (segment.startsWith(".")) {
                return PathValidationResult.invalid("Hidden files not allowed");
            }

            safePath = safePath.resolve(segment);
        }

        // Normalize and verify still within base directory
        Path normalizedPath = safePath.normalize();
        if (!normalizedPath.startsWith(BASE_UPLOAD_DIR)) {
            return PathValidationResult.invalid("Path escapes base directory");
        }

        return PathValidationResult.valid(normalizedPath);
    }

    private boolean isUserAuthorizedForPath(String userId, Path path) {
        // User can only access files in their own directory
        // Expected structure: /uploads/{userId}/...
        Path userDir = BASE_UPLOAD_DIR.resolve(userId).normalize();
        return path.startsWith(userDir);
    }

    private boolean isRateLimited(String clientIP) {
        long now = System.currentTimeMillis();
        Long lastRequest = rateLimitMap.get(clientIP);
        if (lastRequest != null && (now - lastRequest) < 100) { // 100ms between requests
            return true;
        }
        rateLimitMap.put(clientIP, now);
        return false;
    }

    private String getClientIP(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String getSecureContentType(String filename) {
        String lower = filename.toLowerCase();
        if (lower.endsWith(".pdf")) return "application/pdf";
        if (lower.endsWith(".png")) return "image/png";
        if (lower.endsWith(".jpg") || lower.endsWith(".jpeg")) return "image/jpeg";
        if (lower.endsWith(".txt")) return "text/plain";
        return "application/octet-stream"; // Safe default
    }

    private String sanitizeFilenameForHeader(String filename) {
        // Remove any characters that could break Content-Disposition header
        return filename.replaceAll("[^a-zA-Z0-9._-]", "_");
    }

    // Inner class for validation results
    private static class PathValidationResult {
        private final boolean valid;
        private final Path resolvedPath;
        private final String reason;

        private PathValidationResult(boolean valid, Path path, String reason) {
            this.valid = valid;
            this.resolvedPath = path;
            this.reason = reason;
        }

        static PathValidationResult valid(Path path) {
            return new PathValidationResult(true, path, null);
        }

        static PathValidationResult invalid(String reason) {
            return new PathValidationResult(false, null, reason);
        }

        boolean isValid() { return valid; }
        Path getResolvedPath() { return resolvedPath; }
        String getReason() { return reason; }
    }
}
