package main

import (
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadDir = "/var/app/uploads"

func secureDownloadHandler(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("file")
	if filename == "" {
		http.Error(w, "Missing file parameter", http.StatusBadRequest)
		return
	}

	// SECURITY: Clean the filename to remove path traversal sequences
	cleanFilename := filepath.Clean(filename)

	// SECURITY: Reject any path with directory components
	if strings.ContainsAny(cleanFilename, "/\\") || cleanFilename == ".." {
		log.Printf("SECURITY: Path traversal attempt blocked: %s from %s", 
			filename, r.RemoteAddr)
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// SECURITY: Use only the base filename
	baseFilename := filepath.Base(cleanFilename)

	// SECURITY: Construct full path and verify it's within allowed directory
	fullPath := filepath.Join(uploadDir, baseFilename)
	absPath, err := filepath.Abs(fullPath)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	absUploadDir, _ := filepath.Abs(uploadDir)

	// CRITICAL: Verify the resolved path is within the upload directory
	if !strings.HasPrefix(absPath, absUploadDir+string(os.PathSeparator)) {
		log.Printf("SECURITY: Path escape attempt blocked: %s -> %s from %s", 
			filename, absPath, r.RemoteAddr)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	file, err := os.Open(absPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	// SECURITY: Verify it's a regular file, not a symlink or directory
	fileInfo, err := file.Stat()
	if err != nil || !fileInfo.Mode().IsRegular() {
		http.Error(w, "Invalid file", http.StatusBadRequest)
		return
	}

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", "attachment; filename=\""+baseFilename+"\"")
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", secureDownloadHandler)
	http.ListenAndServe(":8080", nil)
}
