	// Step 3: Reject absolute paths and paths starting with ..
	if filepath.IsAbs(cleanPath) || strings.HasPrefix(cleanPath, "..") {
		return "", fmt.Errorf("absolute or parent paths not allowed")
	}

	// Step 4: Build full path and resolve any remaining symlinks
	fullPath := filepath.Join(fs.baseDir, cleanPath)

	// Step 5: Resolve to absolute path (follows symlinks)
	resolvedPath, err := filepath.EvalSymlinks(fullPath)
	if err != nil {
		// File might not exist yet, use Abs for new files
		resolvedPath, err = filepath.Abs(fullPath)
		if err != nil {
			return "", fmt.Errorf("invalid path resolution")
		}
	}

	// Step 6: Resolve base directory to compare
	resolvedBase, err := filepath.EvalSymlinks(fs.baseDir)
	if err != nil {
		resolvedBase, _ = filepath.Abs(fs.baseDir)
	}

	// Step 7: CRITICAL - Verify resolved path is within base directory
	if !strings.HasPrefix(resolvedPath, resolvedBase+string(os.PathSeparator)) &&
		resolvedPath != resolvedBase {
		return "", fmt.Errorf("path traversal detected")
	}

	// Step 8: Validate file extension
	ext := strings.ToLower(filepath.Ext(resolvedPath))
	if ext != "" && !fs.allowedExt[ext] {
		return "", fmt.Errorf("file type not allowed: %s", ext)
	}

	return resolvedPath, nil
}

// CheckUserAuthorization verifies user has permission to access the file
func (fs *FileService) CheckUserAuthorization(ctx context.Context, userID, filePath string) (bool, error) {
	// Extract user directory from path
	relPath, err := filepath.Rel(fs.baseDir, filePath)
	if err != nil {
		return false, err
	}

	parts := strings.Split(relPath, string(os.PathSeparator))
	if len(parts) < 1 {
		return false, fmt.Errorf("invalid path structure")
	}

	// First directory should be user's ID or they need explicit permission
	pathOwner := parts[0]

	// Check if user owns this path
	if pathOwner == userID {
		return true, nil
	}

	// Check for explicit sharing permission in database
	var permitted bool
	err = fs.db.QueryRowContext(ctx,
		`SELECT EXISTS(
			SELECT 1 FROM file_permissions 
			WHERE file_owner = $1 
			AND granted_to = $2 
			AND file_path = $3
			AND expires_at > NOW()
		)`,
		pathOwner, userID, relPath,
	).Scan(&permitted)

	return permitted, err
}

// AuditLog records file access attempts
func (fs *FileService) AuditLog(ctx context.Context, access FileAccess) {
	_, err := fs.db.ExecContext(ctx,
		`INSERT INTO file_access_log 
		(user_id, file_path, access_time, ip_address, action, success, reason)
		VALUES ($1, $2, $3, $4, $5, $6, $7)`,
		access.UserID, access.FilePath, access.AccessTime,
		access.IPAddress, access.Action, access.Success, access.Reason,
	)
	if err != nil {
		log.Printf("ERROR: Failed to write audit log: %v", err)
	}
}

// GenerateSecureToken creates a time-limited download token
func (fs *FileService) GenerateSecureToken(ctx context.Context, userID, filePath string) (string, error) {
	tokenBytes := make([]byte, 32)
	if _, err := rand.Read(tokenBytes); err != nil {
		return "", err
	}
	token := hex.EncodeToString(tokenBytes)

	_, err := fs.db.ExecContext(ctx,
		`INSERT INTO download_tokens (token, user_id, file_path, expires_at)
		VALUES ($1, $2, $3, $4)`,
		token, userID, filePath, time.Now().Add(5*time.Minute),
	)
	return token, err
}

// SecureFileHandler handles file downloads with full security
func (fs *FileService) SecureFileHandler(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()

	// Get authenticated user from context (set by auth middleware)
	userID, ok := ctx.Value("user_id").(string)
	if !ok || userID == "" {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	requestedPath := r.URL.Query().Get("path")
	if requestedPath == "" {
		http.Error(w, "Missing path parameter", http.StatusBadRequest)
		return
	}

	// Initialize audit record
	audit := FileAccess{
		UserID:     userID,
		FilePath:   requestedPath,
		AccessTime: time.Now(),
		IPAddress:  r.RemoteAddr,
		Action:     "DOWNLOAD",
	}

	// Validate path security
	validatedPath, err := fs.ValidatePath(requestedPath)
	if err != nil {
		audit.Success = false
		audit.Reason = fmt.Sprintf("Path validation failed: %v", err)
		fs.AuditLog(ctx, audit)
		log.Printf("SECURITY ALERT: Path traversal attempt by user %s: %s -> %v", 
			userID, requestedPath, err)
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	// Check user authorization
	authorized, err := fs.CheckUserAuthorization(ctx, userID, validatedPath)
	if err != nil || !authorized {
		audit.Success = false
		audit.Reason = "Authorization denied"
		fs.AuditLog(ctx, audit)
		log.Printf("SECURITY: Unauthorized file access attempt by user %s: %s", 
			userID, validatedPath)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// Open and verify file
	file, err := os.Open(validatedPath)
	if err != nil {
		audit.Success = false
		audit.Reason = "File not found"
		fs.AuditLog(ctx, audit)
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	// Verify it's a regular file
	fileInfo, err := file.Stat()
	if err != nil || !fileInfo.Mode().IsRegular() {
		audit.Success = false
		audit.Reason = "Invalid file type"
		fs.AuditLog(ctx, audit)
		http.Error(w, "Invalid file", http.StatusBadRequest)
		return
	}

	// Record successful access
	audit.Success = true
	audit.Reason = "OK"
	fs.AuditLog(ctx, audit)

	// Set secure headers
	filename := filepath.Base(validatedPath)
	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", 
		fmt.Sprintf("attachment; filename=%q", filename))
	w.Header().Set("Content-Length", fmt.Sprintf("%d", fileInfo.Size()))
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "no-store")

	io.Copy(w, file)
}

func main() {
	db, err := sql.Open("postgres", os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	fs := NewFileService("/var/app/uploads", db)

	http.HandleFunc("/api/files/download", fs.SecureFileHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
